'DECLARE
    v_id_med NUMBER;
    v_unidad_medida VARCHAR2(10);
    v_dosis NUMBER;
BEGIN
    -- Buscamos el ID del medicamento basado en el nombre que envía la IA
    BEGIN
        SELECT id_medicamento, UNIDAD_MEDIDA, DOSIS_ESPERADA 
        INTO v_id_med, v_unidad_medida, v_dosis
        FROM cat_medicamentos 
        WHERE UPPER(nombre) LIKE ''%'' || UPPER(:nombre_medicamento) || ''%'' 
        AND estado = ''ACTIVO'' 
        FETCH FIRST 1 ROWS ONLY; -- Previene error si hay nombres similares
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            -- Si la IA entendió mal el nombre o no existe, devolvemos error
            :status_code := 404;
            RETURN;
    END;

    --TODO: Por defecto debe trar unidad de medida del catalogo de medicamentos,
    -- a menos que en la instrucción venga una diferente

    INSERT INTO registro_medicacion (id_medicamento, dosis, unidad_medida, notas)
    VALUES (v_id_med, NVL(:dosis,v_dosis), v_unidad_medida, :notas);
    
    :status_code := 201' || ';
EXCEPTION
    WHEN OTHERS THEN
        :status_code := 400;
END;');

