  l_volumen_ultima_infusion_ml parametros_dialisis.volumen_ultima_infusion_ml%type;
BEGIN
    BEGIN
        SELECT cantidad_infusiones, volumen_infusion_ml, tiempo_perman_infusion_min, tiempo_total_tratam_horas, tiene_ultima_infusion, volumen_ultima_infusion_ml
        INTO l_cantidad_infusiones, l_volumen_infusion_ml, l_tiempo_perman_infusion_min, l_tiempo_total_tratam_horas, l_tiene_ultima_infusion, l_volumen_ultima_infusion_ml
        FROM PARAMETROS_DIALISIS
       WHERE fecha_registro = (SELECT MAX(fecha_registro) FROM parametros_dialisis);
    END;
    INSERT INTO registro_dialisis (
        ultrafi' || 'ltracion_ml, drenaje_inicial_ml, cantidad_infusiones, volumen_infusion_ml, 
        tiempo_perman_infusion_min, TIEMPO_TOTAL_TRATAM_HORAS, tiene_ultima_infusion, volumen_ultima_infusion_ml, notas
    ) VALUES (
        :ultrafiltracion_ml, :drenaje_inicial_ml, l_cantidad_infusiones, l_volumen_infusion_ml, 
        l_tiempo_perman_infusion_min, l_tiempo_total_tratam_horas, l_tiene_ultima_infusion, l_volumen_ultima_infusion_ml, :notas
    );
    
    :status_code := 201;
EXCEPTION
    WHEN OTHERS THEN
        :status_code := 400;
END;');

